import React from 'react';
import './MenuCard.css';

const MenuCard = ({ title, description, price, imageUrl }) => {
  return (
    <div className="menu-card glass-panel">
      <div className="menu-card-image">
        <img src={imageUrl || "https://images.unsplash.com/photo-1497935586351-b67a49e012bf?auto=format&fit=crop&w=500&q=80"} alt={title} />
        <div className="menu-card-price">${price.toFixed(2)}</div>
      </div>
      <div className="menu-card-content">
        <h3>{title}</h3>
        <p>{description}</p>
        <button className="btn-add-cart">Add to Cart</button>
      </div>
    </div>
  );
};

export default MenuCard;

import React from 'react';
import './Navbar.css';

const Navbar = () => {
  return (
    <nav className="navbar glass-panel">
      <div className="navbar-container">
        <div className="navbar-brand">
          <h1>Smart Cafe</h1>
        </div>
        <ul className="navbar-links">
          <li><a href="#home">Home</a></li>
          <li><a href="#menu">Menu</a></li>
          <li><a href="#about">About</a></li>
          <li><a href="#contact">Contact</a></li>
        </ul>
        <div className="navbar-actions">
          <button className="cart-btn">
            🛒 <span className="cart-badge">0</span>
          </button>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation, Outlet } from 'react-router-dom';
import { supabase } from '../lib/supabase';
import { 
  LayoutGrid, 
  Utensils, 
  QrCode, 
  ShoppingBag, 
  MessageSquare, 
  History, 
  Settings, 
  Bell, 
  Coffee,
  ArrowLeft,
  FileText,
  ClipboardList
} from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';
import './OwnerLayout.css';

const OwnerLayout = ({ activeTab }) => {
  const navigate = useNavigate();
  const location = useLocation();
  const [shop, setShop] = useState(null);
  const [user, setUser] = useState(null);
  const [notifications, setNotifications] = useState([]);
  const [isNotifOpen, setIsNotifOpen] = useState(false);
  const [loading, setLoading] = useState(true);
  const [orders, setOrders] = useState([]);
  const [menuViews, setMenuViews] = useState(0);
  const [showNewOrderAlert, setShowNewOrderAlert] = useState(false);
  const { lang, setLang, t } = useLanguage();

  // Navigation Items for Desktop Sidebar
  const sidebarItems = [
    { id: 'dashboard', label: t.dashboard, path: '/dashboard', icon: LayoutGrid },
    { id: 'menu', label: t.menu, path: '/menu-builder', icon: Utensils },
    { id: 'qr-code', label: t.qrCodes, path: '/qr-code', icon: QrCode },
    { id: 'orders', label: t.orders, path: '/orders', icon: ClipboardList },
    { id: 'feedback', label: t.feedback, path: '/feedback', icon: MessageSquare },
    { id: 'history', label: t.history, path: '/history', icon: History },
    { id: 'settings', label: t.settings, path: '/settings', icon: Settings }
  ];

  useEffect(() => {
    let isMounted = true;
    let channel;

    const fetchData = async () => {
      try {
        const { data: { user: authUser } } = await supabase.auth.getUser();
        if (!isMounted) return;
        if (!authUser) {
          navigate('/register');
          return;
        }
        setUser(authUser);

        // Fetch shop details
        const { data: shops } = await supabase.from('shops').select('*').eq('user_id', authUser.id).limit(1);
        if (!isMounted) return;
        if (shops && shops.length > 0) {
          const s = shops[0];
          setShop(s);

          // Fetch notifications
          const { data: notifs } = await supabase.from('notifications')
            .select('*')
            .eq('shop_id', s.id)
            .order('created_at', { ascending: false })
            .limit(20);
          if (!isMounted) return;
          if (notifs) setNotifications(notifs);

          // Fetch active orders (pending, preparing, ready)
          const { data: activeOrders } = await supabase
            .from('orders')
            .select('*, order_items(*)')
            .eq('shop_id', s.id)
            .neq('status', 'rejected')
            .neq('status', 'delivered')
            .order('created_at', { ascending: false });
          if (!isMounted) return;
          if (activeOrders) setOrders(activeOrders);

          // Fetch initial menu views
          const { count: viewsCount } = await supabase.from('menu_views')
            .select('*', { count: 'exact', head: true })
            .eq('shop_id', s.id);
          if (!isMounted) return;
          if (viewsCount !== null) setMenuViews(viewsCount);

          // Subscribe to combined realtime updates (notifications, views, orders) with unique channel name
          channel = supabase.channel(`realtime-owner-${s.id}-${Date.now()}`)
            .on('postgres_changes', {
              event: 'INSERT',
              schema: 'public',
              table: 'notifications',
              filter: `shop_id=eq.${s.id}`
            }, (payload) => {
              setNotifications(prev => [payload.new, ...prev].slice(0, 20));
            })
            .on('postgres_changes', {
              event: 'INSERT',
              schema: 'public',
              table: 'menu_views',
              filter: `shop_id=eq.${s.id}`
            }, () => {
              setMenuViews(prev => prev + 1);
            })
            .on('postgres_changes', {
              event: '*',
              schema: 'public',
              table: 'orders',
              filter: `shop_id=eq.${s.id}`
            }, async (payload) => {
              if (payload.eventType === 'INSERT') {
                const { data: newOrder } = await supabase
                  .from('orders')
                  .select('*, order_items(*)')
                  .eq('id', payload.new.id)
                  .single();
                if (newOrder) {
                  setOrders(prev => [newOrder, ...prev]);
                  setShowNewOrderAlert(true);
                  setTimeout(() => setShowNewOrderAlert(false), 5000);
                }
              } else if (payload.eventType === 'UPDATE') {
                const updated = payload.new;
                if (updated.status === 'rejected' || updated.status === 'delivered') {
                  setOrders(prev => prev.filter(o => o.id !== updated.id));
                } else {
                  setOrders(prev => prev.map(o => o.id === updated.id ? { ...o, ...updated } : o));
                }
              } else if (payload.eventType === 'DELETE') {
                setOrders(prev => prev.filter(o => o.id !== payload.old.id));
              }
            })
            .subscribe();
        } else {
          // If shop is not setup yet
          navigate('/shop-setup');
        }
      } catch (err) {
        console.error('Error fetching layout data:', err);
      } finally {
        if (isMounted) setLoading(false);
      }
    };

    fetchData();

    return () => {
      isMounted = false;
      if (channel) {
        supabase.removeChannel(channel);
      }
    };
  }, [navigate]);

  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh', backgroundColor: 'var(--color-bg)' }}>
        <div style={{ width: '40px', height: '40px', border: '4px solid var(--color-surface)', borderTop: '4px solid var(--color-accent)', borderRadius: '50%', animation: 'spin 1s linear infinite' }}></div>
        <style>{`@keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }`}</style>
      </div>
    );
  }

  const handleMarkAllRead = async () => {
    const unreadIds = notifications.filter(n => !n.is_read).map(n => n.id);
    if (unreadIds.length > 0) {
      await supabase.from('notifications').update({ is_read: true }).in('id', unreadIds);
      setNotifications(notifications.map(n => ({ ...n, is_read: true })));
    }
  };

  const handleNotificationClick = async (n) => {
    if (!n.is_read) {
      await supabase.from('notifications').update({ is_read: true }).eq('id', n.id);
      setNotifications(notifications.map(notif => notif.id === n.id ? { ...notif, is_read: true } : notif));
    }
    // Navigate if notification contains details
    if (n.type === 'feedback') {
      navigate('/feedback');
    } else if (n.type === 'order') {
      navigate('/orders');
    }
  };

  const getActiveTab = () => {
    if (activeTab) return activeTab;
    const path = location.pathname;
    if (path.includes('dashboard')) return 'dashboard';
    if (path.includes('menu-builder')) return 'menu';
    if (path.includes('qr-code')) return 'qr-code';
    if (path.includes('orders')) return 'orders';
    if (path.includes('feedback')) return 'feedback';
    if (path.includes('history')) return 'history';
    if (path.includes('settings')) return 'settings';
    return 'dashboard';
  };

  const currentTab = getActiveTab();

  return (
    <div className="owner-layout">
      {/* 1. Left Sidebar - Desktop/Tablet */}
      <aside className="owner-sidebar">
        <div className="sidebar-logo-container">
          <div className="logo-circle">
            <span className="logo-letter">B</span>
          </div>
          <span className="sidebar-logo-text">B/N Line</span>
        </div>

        <nav className="sidebar-nav">
          {sidebarItems.map(item => {
            const Icon = item.icon;
            const isActive = currentTab === item.id;
            return (
              <button
                key={item.id}
                className={`sidebar-nav-item ${isActive ? 'active' : ''}`}
                onClick={() => navigate(item.path)}
              >
                <Icon className="sidebar-icon" size={20} />
                <span className="sidebar-label">{item.label}</span>
              </button>
            );
          })}
        </nav>
      </aside>

      {/* 2. Right Container */}
      <div className="owner-main-container">
        {/* Top bar header */}
        <header className="owner-top-header">
          {/* Left part of top bar */}
          <div className="top-header-left">
            {/* Mobile View: Back arrow & logo */}
            <div className="mobile-header-info">
              <button 
                onClick={() => navigate(-1)} 
                className="mobile-back-btn"
              >
                <ArrowLeft size={24} />
              </button>
              {shop?.logo_url ? (
                <img src={shop.logo_url} alt="Shop Logo" className="mobile-shop-logo" />
              ) : (
                <div className="mobile-shop-logo fallback">
                  <Coffee size={20} />
                </div>
              )}
            </div>

            {/* Cafe Title (Text-only on desktop, matches PNG) */}
            <h1 className="top-header-title">{shop?.name || 'PSRV Cafe'}</h1>
          </div>

          {/* Right part of top bar */}
          <div className="top-header-right">
            {/* Language Toggle switch */}
            <div className="language-toggle-pill" onClick={() => setLang(lang === 'EN' ? 'TE' : 'EN')}>
              <span className={`lang-option ${lang === 'TE' ? 'active' : ''}`}>TE</span>
              <span className={`lang-option ${lang === 'EN' ? 'active' : ''}`}>EN</span>
            </div>

            {/* Notifications Dropdown */}
            <div className="top-notification-wrapper">
              <button className="top-notification-btn" onClick={() => setIsNotifOpen(!isNotifOpen)}>
                <Bell size={22} />
                {notifications.filter(n => !n.is_read).length > 0 && (
                  <span className="top-notification-dot"></span>
                )}
              </button>

              {isNotifOpen && (
                <div className="top-notification-dropdown">
                  <div className="top-notification-header">
                    <h3>{t.notifications}</h3>
                    <button onClick={handleMarkAllRead} className="mark-read-btn">
                      {t.markAllRead}
                    </button>
                  </div>

                  <div className="top-notification-list">
                    {notifications.length === 0 ? (
                      <div className="top-notification-empty">{t.noNotifications}</div>
                    ) : (
                      notifications.map(n => (
                        <div 
                          key={n.id} 
                          className={`top-notification-item ${n.is_read ? '' : 'unread'}`}
                          onClick={() => {
                            handleNotificationClick(n);
                            setIsNotifOpen(false);
                          }}
                        >
                          <div className="top-notification-icon-wrapper" style={{ 
                            backgroundColor: n.type === 'feedback' ? 'rgba(76, 175, 80, 0.1)' : 'rgba(255, 109, 0, 0.1)', 
                            color: n.type === 'feedback' ? '#4CAF50' : '#ff6b35' 
                          }}>
                            {n.type === 'feedback' ? <MessageSquare size={16} /> : <Bell size={16} />}
                          </div>
                          <div className="top-notification-content">
                            <p className="top-notification-title">{n.title}</p>
                            <p className="top-notification-message">{n.message}</p>
                            <p className="top-notification-time">{new Date(n.created_at).toLocaleString()}</p>
                          </div>
                        </div>
                      ))
                    )}
                  </div>
                </div>
              )}
            </div>
          </div>
        </header>

        {/* Page Inner Content */}
        <div className="owner-page-content">
          <Outlet context={{ 
            shop, 
            setShop, 
            user, 
            orders, 
            setOrders, 
            menuViews, 
            setMenuViews, 
            showNewOrderAlert, 
            setShowNewOrderAlert 
          }} />
        </div>
      </div>

      {/* 3. Bottom Navigation - Mobile View only (preserves current structure) */}
      <nav className="dash-bottom-nav">
        <a className={`dash-nav-item ${currentTab === 'dashboard' ? 'active' : ''}`} onClick={() => navigate('/dashboard')}>
          <LayoutGrid size={24} />
          <span className="dash-nav-label">{t.dashboard}</span>
        </a>
        <a className={`dash-nav-item ${currentTab === 'menu' ? 'active' : ''}`} onClick={() => navigate('/menu-builder')}>
          <Utensils size={24} />
          <span className="dash-nav-label">{t.menu}</span>
        </a>
        <a className={`dash-nav-item ${currentTab === 'qr-code' ? 'active' : ''}`} onClick={() => navigate('/qr-code')} style={{ position: 'relative', top: '-10px', backgroundColor: 'var(--color-bg)', padding: '8px', borderRadius: '50%', color: 'var(--color-accent)', border: '2px solid var(--color-surface)' }}>
          <QrCode size={28} />
        </a>
        <a className={`dash-nav-item ${currentTab === 'history' ? 'active' : ''}`} onClick={() => navigate('/history')}>
          <FileText size={24} />
          <span className="dash-nav-label">{t.history}</span>
        </a>
        <a className={`dash-nav-item ${currentTab === 'settings' ? 'active' : ''}`} onClick={() => navigate('/settings')}>
          <Settings size={24} />
          <span className="dash-nav-label">{t.settings}</span>
        </a>
      </nav>
    </div>
  );
};

export default OwnerLayout;

