import React, { useState, useEffect } from 'react';
import { useNavigate, useOutletContext } from 'react-router-dom';
import { QrCode, ArrowRight, Download, Share2, ArrowLeft } from 'lucide-react';
import { QRCodeCanvas } from 'qrcode.react';
import { supabase } from '../lib/supabase';
import '../index.css';
import { useLanguage } from '../contexts/LanguageContext';

const QRCodeGeneration = () => {
  const navigate = useNavigate();
  const { shop } = useOutletContext();
  const [shopId, setShopId] = useState("");
  const [shopName, setShopName] = useState("");
  const [ownerUniqueId, setOwnerUniqueId] = useState("");
  const [loading, setLoading] = useState(true);
  const { t } = useLanguage();
  const tableNumber = 1;
  const baseUrl = window.location.origin;
  const qrValue = ownerUniqueId ? `${baseUrl}/menu/${ownerUniqueId}?table=${tableNumber}` : '';

  useEffect(() => {
    if (!shop) return;
    setShopId(shop.id);
    setShopName(shop.name);
    setOwnerUniqueId(shop.owner_unique_id || "ID Not Generated");
    setLoading(false);
  }, [shop?.id, shop?.name, shop?.owner_unique_id]);

  const handleDownload = () => {
    const canvas = document.getElementById("qr-gen");
    if (canvas) {
      const pngUrl = canvas.toDataURL("image/png").replace("image/png", "image/octet-stream");
      let downloadLink = document.createElement("a");
      downloadLink.href = pngUrl;
      downloadLink.download = `table-${tableNumber}.png`;
      document.body.appendChild(downloadLink);
      downloadLink.click();
      document.body.removeChild(downloadLink);
    }
  };

  const handleShare = async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: `Table ${tableNumber} QR Code`,
          text: `Scan this to view the menu for Table ${tableNumber}`,
          url: qrValue,
        });
      } catch (err) {
        console.error('Error sharing:', err);
      }
    } else {
      navigator.clipboard.writeText(qrValue);
      alert('Link copied to clipboard!');
    }
  };

  return (
    <div className="app-container" style={{ paddingTop: '2rem' }}>
      <button 
        onClick={() => navigate(-1)} 
        style={{ background: 'rgba(255,255,255,0.1)', border: '1px solid var(--glass-border)', color: 'var(--color-text-main)', padding: '10px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', marginBottom: '2rem', width: '42px', height: '42px', transition: 'var(--transition-fast)' }}
      >
        <ArrowLeft size={20} />
      </button>

      <div style={{ textAlign: 'center', marginBottom: '2.5rem' }}>
        <h2 style={{ fontSize: '2rem', marginBottom: '0.5rem' }}>{t.qrCodeGeneration}</h2>
        <p style={{ color: 'var(--color-text-muted)' }}>Print and place this on your tables for customers to scan.</p>
      </div>

      <div className="glass-panel" style={{ padding: '3rem', borderRadius: '24px', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '2rem', maxWidth: '400px', width: '100%', marginBottom: '3rem' }}>

        {loading ? (
          <div style={{ background: 'white', padding: '24px', borderRadius: '16px', boxShadow: '0 10px 30px rgba(0,0,0,0.5)', width: '248px', height: '248px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <p style={{ color: '#9ca3af' }}>{t.generatingQR}</p>
          </div>
        ) : (
          <div style={{ background: 'white', padding: '24px', borderRadius: '16px', boxShadow: '0 10px 30px rgba(0,0,0,0.5)' }}>
            <QRCodeCanvas id="qr-gen" value={qrValue} size={200} level="H" includeMargin={false} />
          </div>
        )}

        <div style={{ textAlign: 'center' }}>
          <h3 style={{ margin: '0 0 0.5rem 0', color: 'var(--color-accent)' }}>{shopName || 'Your Shop'} - Table {tableNumber}</h3>
          <p style={{ color: 'var(--color-text-muted)', fontSize: '0.8rem', wordBreak: 'break-all', margin: 0, opacity: 0.6 }}>{qrValue}</p>
        </div>

        <div style={{ display: 'flex', gap: '1rem', width: '100%' }}>
          <button onClick={handleDownload} style={{ flex: 1, padding: '12px', borderRadius: '8px', border: '1px solid var(--glass-border)', background: 'var(--color-surface)', color: 'var(--color-text-main)', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '8px', cursor: 'pointer', transition: 'var(--transition-fast)' }} onMouseOver={e => e.currentTarget.style.background = 'var(--glass-border)'} onMouseOut={e => e.currentTarget.style.background = 'var(--color-surface)'}>
            <Download size={18} /> {t.downloadQR}
          </button>
          <button onClick={handleShare} style={{ flex: 1, padding: '12px', borderRadius: '8px', border: '1px solid var(--glass-border)', background: 'var(--color-surface)', color: 'var(--color-text-main)', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '8px', cursor: 'pointer', transition: 'var(--transition-fast)' }} onMouseOver={e => e.currentTarget.style.background = 'var(--glass-border)'} onMouseOut={e => e.currentTarget.style.background = 'var(--color-surface)'}>
            <Share2 size={18} /> Share
          </button>
        </div>

        <p style={{ fontSize: '0.8rem', color: 'var(--color-text-muted)', textAlign: 'center', margin: 0 }}>
          * We'll start with just one table for now. You can generate more from the dashboard later.
        </p>
      </div>

      <button onClick={() => navigate('/menu-builder')} className="btn-primary" style={{ display: 'flex', alignItems: 'center', gap: '12px', padding: '16px 32px', fontSize: '1.1rem' }}>
        Next: Build Your Menu <ArrowRight size={20} />
      </button>

      </div>
  );
};

export default QRCodeGeneration;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Coffee, ArrowRight } from 'lucide-react';
import { supabase } from '../lib/supabase';
import '../index.css';
import { useLanguage } from '../contexts/LanguageContext';

const RegisterLogin = () => {
  const [isLogin, setIsLogin] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();
  const { t } = useLanguage();

  useEffect(() => {
    const checkAuth = async () => {
      const { data: { user } } = await supabase.auth.getUser();
      if (user) {
        navigate('/dashboard');
      }
    };
    checkAuth();
  }, [navigate]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      if (isLogin) {
        const { data, error } = await supabase.auth.signInWithPassword({ email, password });
        if (error) throw error;
        navigate('/shop-setup');
      } else {
        const { data, error } = await supabase.auth.signUp({ 
          email, 
          password,
          options: { data: { full_name: fullName } }
        });
        if (error) throw error;
        navigate('/shop-setup');
      }
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
    try {
      const { error } = await supabase.auth.signInWithOAuth({
        provider: 'google',
        options: { redirectTo: window.location.origin + '/shop-setup' }
      });
      if (error) throw error;
    } catch (err) {
      setError(err.message);
    }
  };

  return (
    <div className="app-container">
      <div className="glass-panel" style={{ width: '100%', maxWidth: '400px', padding: '2.5rem', borderRadius: '16px' }}>
        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', marginBottom: '2rem' }}>
          <div style={{ background: 'var(--color-primary)', padding: '12px', borderRadius: '50%', marginBottom: '1rem' }}>
            <Coffee size={32} color="var(--color-accent)" />
          </div>
          <h2 style={{ textAlign: 'center', margin: 0 }}>Smart Cafe</h2>
          <p style={{ color: 'var(--color-text-muted)', marginTop: '0.5rem' }}>
            {isLogin ? t.loginTitle : t.registerTitle}
          </p>
        </div>

        {error && <div style={{ background: 'rgba(255,0,0,0.1)', color: '#ff6b6b', padding: '10px', borderRadius: '8px', marginBottom: '1rem', fontSize: '0.9rem', textAlign: 'center' }}>{error}</div>}

        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '1.25rem' }}>
          {!isLogin && (
            <div>
              <label style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.9rem', color: 'var(--color-text-muted)' }}>Full Name</label>
              <input 
                type="text" 
                required 
                value={fullName}
                onChange={e => setFullName(e.target.value)}
                style={{ width: '100%', padding: '12px', borderRadius: '8px', border: '1px solid var(--glass-border)', background: 'var(--color-surface)', color: 'var(--color-text-main)', outline: 'none' }} 
                placeholder="John Doe" 
              />
            </div>
          )}

          <div>
            <label style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.9rem', color: 'var(--color-text-muted)' }}>{t.email}</label>
            <input 
              type="email" 
              required 
              value={email}
              onChange={e => setEmail(e.target.value)}
              style={{ width: '100%', padding: '12px', borderRadius: '8px', border: '1px solid var(--glass-border)', background: 'var(--color-surface)', color: 'var(--color-text-main)', outline: 'none' }} 
              placeholder="owner@cafe.com" 
            />
          </div>

          <div>
            <label style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.9rem', color: 'var(--color-text-muted)' }}>{t.password}</label>
            <input 
              type="password" 
              required 
              value={password}
              onChange={e => setPassword(e.target.value)}
              style={{ width: '100%', padding: '12px', borderRadius: '8px', border: '1px solid var(--glass-border)', background: 'var(--color-surface)', color: 'var(--color-text-main)', outline: 'none' }} 
              placeholder="••••••••" 
            />
          </div>

          <button type="submit" disabled={loading} className="btn-primary" style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '8px', marginTop: '1rem', opacity: loading ? 0.7 : 1 }}>
            {loading ? (isLogin ? t.loggingIn : t.registering) : (isLogin ? t.login : t.register)} <ArrowRight size={18} />
          </button>

          <div style={{ display: 'flex', alignItems: 'center', margin: '0.5rem 0' }}>
            <div style={{ flex: 1, height: '1px', background: 'var(--glass-border)' }}></div>
            <span style={{ padding: '0 10px', color: 'var(--color-text-muted)', fontSize: '0.8rem' }}>OR</span>
            <div style={{ flex: 1, height: '1px', background: 'var(--glass-border)' }}></div>
          </div>

          <button type="button" onClick={handleGoogleLogin} style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '12px', padding: '12px', borderRadius: '30px', border: 'none', background: 'white', color: '#333', fontSize: '1rem', fontWeight: '600', cursor: 'pointer', transition: 'transform var(--transition-fast)' }} onMouseOver={e => e.currentTarget.style.transform = 'translateY(-2px)'} onMouseOut={e => e.currentTarget.style.transform = 'translateY(0)'}>
            <img src="https://www.gstatic.com/firebasejs/ui/2.0.0/images/auth/google.svg" alt="Google logo" style={{ width: '20px', height: '20px' }} />
            {isLogin ? 'Sign in with Google' : 'Sign up with Google'}
          </button>
        </form>

        <div style={{ textAlign: 'center', marginTop: '2rem' }}>
          <button 
            onClick={() => setIsLogin(!isLogin)} 
            style={{ background: 'none', border: 'none', color: 'var(--color-text-muted)', fontSize: '0.9rem', cursor: 'pointer', textDecoration: 'underline' }}
          >
            {isLogin ? t.dontHaveAccount : t.alreadyHaveAccount}
          </button>
        </div>
      </div>
    </div>
  );
};

export default RegisterLogin;

